"use strict";(self.webpackChunkcatalog_docs=self.webpackChunkcatalog_docs||[]).push([[53],{1109:t=>{t.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Catalog Overview","href":"/","docId":"intro"},{"type":"category","label":"Catalog Accounts","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-accounts/introduction","docId":"catalog-accounts/introduction"},{"type":"link","label":"Relayer","href":"/catalog-accounts/relayer","docId":"catalog-accounts/relayer"},{"type":"category","label":"Instant Wallet","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-accounts/instant-wallet/introduction","docId":"catalog-accounts/instant-wallet/introduction"},{"type":"link","label":"Guardian","href":"/catalog-accounts/instant-wallet/guardian","docId":"catalog-accounts/instant-wallet/guardian"},{"type":"link","label":"API","href":"/catalog-accounts/instant-wallet/api","docId":"catalog-accounts/instant-wallet/api"}]}]},{"type":"category","label":"Catalog Swaps","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-swaps/introduction","docId":"catalog-swaps/introduction"},{"type":"category","label":"HTLCs","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-swaps/htlcs/introduction","docId":"catalog-swaps/htlcs/introduction"}]},{"type":"link","label":"Insurance","href":"/catalog-swaps/insurance","docId":"catalog-swaps/insurance"},{"type":"link","label":"Resolver","href":"/catalog-swaps/resolver","docId":"catalog-swaps/resolver"}]},{"type":"category","label":"Catalog Wallet","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-wallet/introduction","docId":"catalog-wallet/introduction"},{"type":"link","label":"SDK","href":"/catalog-wallet/sdk","docId":"catalog-wallet/sdk"}]}]},"docs":{"catalog-accounts/instant-wallet/api":{"id":"catalog-accounts/instant-wallet/api","title":"API","description":"Description","sidebar":"tutorialSidebar"},"catalog-accounts/instant-wallet/guardian":{"id":"catalog-accounts/instant-wallet/guardian","title":"Guardian","description":"The Guardian is a co-signing service for the Instant Wallet. The Guardian ensures secure transactions by eliminating the possibility of double spending without the need for confirmation delays. It achieves this by providing a second signature for all account operations, meaning it can guarantee no transaction will be able to override existing ones.","sidebar":"tutorialSidebar"},"catalog-accounts/instant-wallet/introduction":{"id":"catalog-accounts/instant-wallet/introduction","title":"Introduction","description":"An Instant Wallet is a 2-of-2 multi-sig wallet which enables instant transfers and cross-chain swaps, without requiring any form of trust. It does this through the use of the Catalog Guardian, which allows users to bypass confirmation delays. All of the below operations are entirely trustless, and the user maintains full ownership of their funds at each and every step.","sidebar":"tutorialSidebar"},"catalog-accounts/introduction":{"id":"catalog-accounts/introduction","title":"Introduction","description":"Catalog Accounts underpin the way users interact with Web3 through Catalog. These are a set of keypairs and smart contracts that allow users to store assets from any blockchain, including Bitcoin, ERC-20 tokens, and NFTs. A Catalog Account consists of two wallets:","sidebar":"tutorialSidebar"},"catalog-accounts/relayer":{"id":"catalog-accounts/relayer","title":"Relayer","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-swaps/htlcs/introduction":{"id":"catalog-swaps/htlcs/introduction","title":"Introduction","description":"Catalog Swaps use hashed timelock contracts (HTLCs) for execution, which function as a two-way virtual safe.","sidebar":"tutorialSidebar"},"catalog-swaps/insurance":{"id":"catalog-swaps/insurance","title":"Insurance","description":"Catalog has an insurance contract in the event a user fails to complete their side of an swap. The contract uses an oracle to check for proof-of-exclusion, which alongside the Guardian\u2019s signed commitment, enables the user to redeem an equivalent amount of funds from the insurance pool.","sidebar":"tutorialSidebar"},"catalog-swaps/introduction":{"id":"catalog-swaps/introduction","title":"Introduction","description":"Catalog Swaps offer users a way to execute cross-chain swaps atomically, without gas spend and risks of being front-run. Multiple resolvers compete in an auction format to provide the best possible rate for the user.","sidebar":"tutorialSidebar"},"catalog-swaps/resolver":{"id":"catalog-swaps/resolver","title":"Resolver","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-wallet/introduction":{"id":"catalog-wallet/introduction","title":"Introduction","description":"Catalog Wallet is a browser extension that enables seamless cross-chain support for dApps irrespective of which chain they reside on. The extension integrates directly with existing dApps, meaning you can transact Bitcoin and other assets directly on your favorite exchange or NFT marketplace.","sidebar":"tutorialSidebar"},"catalog-wallet/sdk":{"id":"catalog-wallet/sdk","title":"SDK","description":"Work in progress.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Catalog Overview","description":"What is Catalog?","sidebar":"tutorialSidebar"}}}')}}]);